class Solution {
    TreeNode* prev = nullptr;
    int ans = INT_MAX;
    void inorder(TreeNode* n) {
        if (!n) return;
        inorder(n->left);
        if (prev) ans = min(ans, n->val - prev->val);
        prev = n;
        inorder(n->right);
    }
public:
    int getMinimumDifference(TreeNode* root) {
        inorder(root);
        return ans;
    }
};
